import React, { useState } from 'react';
import axios from 'axios';

const AdminModeToggle = ({ onAdminStatusChange }) => {
  const [isAdmin, setIsAdmin] = useState(() => {
    return localStorage.getItem('isAdmin') === 'true';
  });
  const [showPasswordModal, setShowPasswordModal] = useState(false);
  const [password, setPassword] = useState('');
  const [error, setError] = useState(null);
  const [loading, setLoading] = useState(false);

  // 验证管理员密码
  const handleVerifyPassword = async () => {
    if (!password) {
      setError('请输入密码');
      return;
    }

    setLoading(true);
    setError(null);

    try {
      const response = await axios.post('/api/admin/verify', { password });

      if (response.data.success) {
        setIsAdmin(true);
        localStorage.setItem('isAdmin', 'true');
        setShowPasswordModal(false);
        setPassword('');
        if (onAdminStatusChange) {
          onAdminStatusChange(true);
        }
      }
    } catch (err) {
      setError(err.response?.data?.error || '验证失败，请重试');
    } finally {
      setLoading(false);
    }
  };

  // 退出管理员模式
  const handleExitAdmin = () => {
    setIsAdmin(false);
    localStorage.removeItem('isAdmin');
    if (onAdminStatusChange) {
      onAdminStatusChange(false);
    }
  };

  // 处理键盘事件
  const handleKeyPress = (e) => {
    if (e.key === 'Enter') {
      handleVerifyPassword();
    }
  };

  return (
    <>
      <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
        {isAdmin ? (
          <>
            <span style={{ 
              color: '#10b981', 
              fontSize: '14px',
              fontWeight: 'bold',
              display: 'flex',
              alignItems: 'center',
              gap: '5px'
            }}>
              🔐 管理员模式
            </span>
            <button
              onClick={handleExitAdmin}
              style={{
                padding: '6px 12px',
                backgroundColor: '#ef4444',
                color: 'white',
                border: 'none',
                borderRadius: '4px',
                cursor: 'pointer',
                fontSize: '12px',
                transition: 'background-color 0.2s'
              }}
              onMouseOver={(e) => e.target.style.backgroundColor = '#dc2626'}
              onMouseOut={(e) => e.target.style.backgroundColor = '#ef4444'}
            >
              退出管理
            </button>
          </>
        ) : (
          <button
            onClick={() => setShowPasswordModal(true)}
            style={{
              padding: '6px 12px',
              backgroundColor: '#3b82f6',
              color: 'white',
              border: 'none',
              borderRadius: '4px',
              cursor: 'pointer',
              fontSize: '12px',
              transition: 'background-color 0.2s'
            }}
            onMouseOver={(e) => e.target.style.backgroundColor = '#2563eb'}
            onMouseOut={(e) => e.target.style.backgroundColor = '#3b82f6'}
          >
            🔑 管理模式
          </button>
        )}
      </div>

      {/* 密码输入模态框 */}
      {showPasswordModal && (
        <div style={{
          position: 'fixed',
          top: 0,
          left: 0,
          right: 0,
          bottom: 0,
          backgroundColor: 'rgba(0, 0, 0, 0.5)',
          display: 'flex',
          justifyContent: 'center',
          alignItems: 'center',
          zIndex: 1000
        }}>
          <div style={{
            backgroundColor: 'white',
            padding: '30px',
            borderRadius: '8px',
            boxShadow: '0 4px 6px rgba(0, 0, 0, 0.1)',
            minWidth: '320px',
            maxWidth: '400px'
          }}>
            <h3 style={{ margin: '0 0 20px 0', color: '#1f2937' }}>
              输入管理员密码
            </h3>

            <input
              type="password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              onKeyPress={handleKeyPress}
              placeholder="请输入管理员密码"
              autoFocus
              style={{
                width: '100%',
                padding: '10px',
                border: '1px solid #d1d5db',
                borderRadius: '4px',
                fontSize: '14px',
                marginBottom: error ? '10px' : '20px',
                boxSizing: 'border-box'
              }}
            />

            {error && (
              <div style={{
                color: '#ef4444',
                fontSize: '12px',
                marginBottom: '15px'
              }}>
                ⚠️ {error}
              </div>
            )}

            <div style={{ display: 'flex', gap: '10px', justifyContent: 'flex-end' }}>
              <button
                onClick={() => {
                  setShowPasswordModal(false);
                  setPassword('');
                  setError(null);
                }}
                disabled={loading}
                style={{
                  padding: '8px 16px',
                  backgroundColor: '#f3f4f6',
                  color: '#374151',
                  border: 'none',
                  borderRadius: '4px',
                  cursor: loading ? 'not-allowed' : 'pointer',
                  fontSize: '14px'
                }}
              >
                取消
              </button>
              <button
                onClick={handleVerifyPassword}
                disabled={loading}
                style={{
                  padding: '8px 16px',
                  backgroundColor: loading ? '#9ca3af' : '#3b82f6',
                  color: 'white',
                  border: 'none',
                  borderRadius: '4px',
                  cursor: loading ? 'not-allowed' : 'pointer',
                  fontSize: '14px',
                  transition: 'background-color 0.2s'
                }}
              >
                {loading ? '验证中...' : '确认'}
              </button>
            </div>
          </div>
        </div>
      )}
    </>
  );
};

export default AdminModeToggle;
